 &amp;quot; AS o &amp;quot; . &amp;quot;LEFT JOIN &amp;quot; . $GLOBALS\[&amp;#39;ecs&amp;#39;\]-&amp;gt;table(&amp;#39;goods&amp;#39;) . &amp;quot; AS g ON o.goods\_id &amp;#x3D; g.goods\_id &amp;quot; . &amp;quot;LEFT JOIN &amp;quot; . $GLOBALS\[&amp;#39;ecs&amp;#39;\]-&amp;gt;table(&amp;#39;brand&amp;#39;) . &amp;quot; AS b ON g.brand\_id &amp;#x3D; b.brand\_id &amp;quot; . &amp;quot;WHERE o.order\_id &amp;#x3D; &amp;#39;$order\_id&amp;#39; )  p on g.order\_id&amp;#x3D;p.order\_id&amp;quot;; $sql&amp;#x3D;&amp;quot;select *, (g.goods\_price*g.goods\_number) as num\_price, g.goods\_attr from &amp;quot; . $GLOBALS\[&amp;#39;ecs&amp;#39;\]-&amp;gt;table(&amp;#39;goods&amp;#39;) .&amp;quot; gt, &amp;quot; . $GLOBALS\[&amp;#39;ecs&amp;#39;\]-&amp;gt;table(&amp;#39;order\_info&amp;#39;) .&amp;quot; i, &amp;quot; . $GLOBALS\[&amp;#39;ecs&amp;#39;\]-&amp;gt;table(&amp;#39;order\_goods&amp;#39;) .&amp;quot; g where g.order\_id&amp;#x3D;i.order\_id and gt.goods\_id &amp;#x3D; g.goods\_id and i.order\_id &amp;#x3D; &amp;#39;$order\_id&amp;#39;&amp;quot;; $res&amp;#x3D;$db-&amp;gt;getAll($sql); &amp;#x2F;&amp;#x2F;print\_r($res);die; $data.&amp;#x3D;&amp;#39;订单号&amp;#39;.&amp;quot;\\t&amp;quot;; $data.&amp;#x3D;&amp;#39;商品图&amp;#39;.&amp;quot;\\t&amp;quot;; $data.&amp;#x3D;&amp;#39;商品名称&amp;#39;.&amp;quot;\\t&amp;quot;; $data.&amp;#x3D;&amp;#39;商品编号&amp;#39;.&amp;quot;\\t&amp;quot;; $data.&amp;#x3D;&amp;#39;商品单价&amp;#39;.&amp;quot;\\t&amp;quot;; $data.&amp;#x3D;&amp;#39;商品数量&amp;#39;.&amp;quot;\\t&amp;quot;; $data.&amp;#x3D;&amp;#39;合计价格&amp;#39;.&amp;quot;\\t&amp;quot;; $data.&amp;#x3D;&amp;#39;应付金额&amp;#39;.&amp;quot;\\t&amp;quot;; $data.&amp;#x3D;&amp;#39;属性备注&amp;#39;.&amp;quot;\\t\\n&amp;quot;; while (!empty($res)) &amp;#123; foreach ($res as $key&amp;#x3D;&amp;gt;$var) &amp;#123; $a&amp;#x3D;$var\[&amp;#39;goods\_id&amp;#39;\]; foreach ($res as $keys&amp;#x3D;&amp;gt;$vars) &amp;#123; if($a&amp;#x3D;&amp;#x3D;$vars\[&amp;#39;goods\_id&amp;#39;\]) &amp;#123; $res1\[0\]\[&amp;#39;order\_sn&amp;#39;\]&amp;#x3D;$vars\[&amp;#39;order\_sn&amp;#39;\]; $res1\[$key\]\[&amp;#39;goods\_thumb&amp;#39;\]&amp;#x3D;$vars\[&amp;#39;goods\_thumb&amp;#39;\]; $res1\[$key\]\[&amp;#39;goods\_name&amp;#39;\]&amp;#x3D;$vars\[&amp;#39;goods\_name&amp;#39;\]; $res1\[$key\]\[&amp;#39;goods\_sn&amp;#39;\]&amp;#x3D;$vars\[&amp;#39;goods\_sn&amp;#39;\]; $res1\[$key\]\[&amp;#39;goods\_price&amp;#39;\]&amp;#x3D;$vars\[&amp;#39;goods\_price&amp;#39;\]; $res1\[$key\]\[&amp;#39;goods\_number&amp;#39;\]&amp;#x3D;$vars\[&amp;#39;goods\_number&amp;#39;\]; $res1\[0\]\[&amp;#39;goods\_amount&amp;#39;\]&amp;#x3D;$vars\[&amp;#39;goods\_amount&amp;#39;\]; $res1\[0\]\[&amp;#39;order\_amount&amp;#39;\]&amp;#x3D;$vars\[&amp;#39;order\_amount&amp;#39;\]; $res1\[$key\]\[&amp;#39;goods\_attr\_id&amp;#39;\]&amp;#x3D;$vars\[&amp;#39;goods\_attr\_id&amp;#39;\]; unset ($res\[$keys\]); &amp;#125; &amp;#125; &amp;#125; &amp;#125; foreach ($res1 as $key &amp;#x3D;&amp;gt;$var) &amp;#123; $data.&amp;#x3D;$var\[&amp;#39;order\_sn&amp;#39;\].&amp;quot;\\t&amp;quot;; $data.&amp;#x3D;$var\[&amp;#39;goods\_thumb&amp;#39;\].&amp;quot;\\t&amp;quot;; $data.&amp;#x3D;$var\[&amp;#39;goods\_name&amp;#39;\].&amp;quot;\\t&amp;quot;; $data.&amp;#x3D;$var\[&amp;#39;goods\_sn&amp;#39;\].&amp;quot;\\t&amp;quot;; $data.&amp;#x3D;$var\[&amp;#39;goods\_price&amp;#39;\].&amp;quot;\\t&amp;quot;; $data.&amp;#x3D;$var\[&amp;#39;goods\_number&amp;#39;\].&amp;quot;\\t&amp;quot;; $data.&amp;#x3D;$var\[&amp;#39;goods\_amount&amp;#39;\].&amp;quot;\\t&amp;quot;; $data.&amp;#x3D;$var\[&amp;#39;order\_amount&amp;#39;\].&amp;quot;\\t&amp;quot;; $data.&amp;#x3D;$var\[&amp;#39;goods\_attr\_id&amp;#39;\].&amp;quot;\\t&amp;quot;; $data.&amp;#x3D;&amp;quot;\\t\\n&amp;quot;; &amp;#125; if (EC\_CHARSET !&amp;#x3D; &amp;#39;gbk&amp;#39;) &amp;#123; echo $data.ecs\_iconv(EC\_CHARSET, &amp;#39;gbk&amp;#39;, $data) . &amp;quot;\\t&amp;quot;; &amp;#125; else &amp;#123; echo $data.$data. &amp;quot;\\t&amp;quot;; &amp;#125; ?&amp;gt; if (!empty(    $order\_sn\_list))&amp;#123; $goods\_thumb &amp;#x3D; $\_POST\[&amp;#39;goods\_thumb&amp;#39;\]; $img &amp;#x3D; grabImage($goods\_thumb,&amp;quot;&amp;quot;); echo $img; echo &amp;#39;&amp;lt;pre&amp;gt;&amp;lt;img src&amp;#x3D;&amp;quot;&amp;#39;.$img.&amp;#39;&amp;quot;&amp;gt;&amp;lt;&amp;#x2F;pre&amp;gt;&amp;#39;; &amp;#125; &amp;#x2F;&amp;#x2F;下载图片函数 function grabImage($goods\_thumb,$filename&amp;#x3D;&amp;quot;&amp;quot;)&amp;#123; if ($goods\_thumb &amp;#x3D;&amp;#x3D; &amp;quot;&amp;quot;) return false; if($filename &amp;#x3D;&amp;#x3D; &amp;quot;&amp;quot;) &amp;#123; $ext&amp;#x3D;strrchr($goods\_thumb,&amp;quot;.&amp;quot;); &amp;#x2F;&amp;#x2F;获取扩展名 $ext\_arr &amp;#x3D; array(&amp;quot;.gif&amp;quot;,&amp;quot;.png&amp;quot;,&amp;quot;.jpg&amp;quot;,&amp;quot;.bmp&amp;quot;); &amp;#x2F;&amp;#x2F;判断扩展名是否为图片 if (!in\_array($ext, $ext\_arr)) return false; &amp;#x2F;&amp;#x2F;将图片文件名保存为时间戳 $filename &amp;#x3D; time().$ext; &amp;#125; ob\_start(); &amp;#x2F;&amp;#x2F;打开浏览器的缓冲区 readfile($goods\_thumb); &amp;#x2F;&amp;#x2F;将图片读入缓冲区 $img &amp;#x3D; ob\_get\_contents(); &amp;#x2F;&amp;#x2F;获取缓冲区的内容复制给变量$img ob\_end_clean(); &amp;#x2F;&amp;#x2F;关闭并清空缓冲 $fp &amp;#x3D; @fopen($filename,&amp;quot;a&amp;quot;); &amp;#x2F;&amp;#x2F;将文件绑定到流 fwrite($fp,$img); &amp;#x2F;&amp;#x2F;写入文件 fclose($fp); &amp;#x2F;&amp;#x2F;关闭文件之争 return $filename; &amp;#125; ?&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
